refixedKey{\n\t\tServiceID: strings.TrimPrefix(parts[0], GrafanaPrefix),\n\t\tSecret:    parts[1],\n\t\tChecksum:  parts[2],\n\t}\n\tif key.CalculateChecksum() != key.Checksum {\n\t\treturn nil, ErrInvalidApiKey\n\t}\n\n\treturn key, nil\n}\n", "numLines": 97, "startLine": 1, "totalLines": 97}}
